import json

with open('baseline-packages-new.json') as f:
    baseline = json.load(f)
with open('after-cpm-packages.json') as f:
    after = json.load(f)

# Build lookup: project_name -> framework -> package_id -> version
def build_lookup(data):
    lookup = {}
    for proj in data['projects']:
        name = proj['path'].split('/')[-1]
        lookup[name] = {}
        for fw in proj['frameworks']:
            tfm = fw['framework']
            lookup[name][tfm] = {}
            for pkg in fw.get('topLevelPackages', []):
                lookup[name][tfm][pkg['id']] = pkg['resolvedVersion']
    return lookup

b = build_lookup(baseline)
a = build_lookup(after)

changes = []
unchanged = []

for proj in sorted(set(list(b.keys()) + list(a.keys()))):
    for tfm in sorted(set(list(b.get(proj,{}).keys()) + list(a.get(proj,{}).keys()))):
        bp = b.get(proj,{}).get(tfm,{})
        ap = a.get(proj,{}).get(tfm,{})
        for pkg in sorted(set(list(bp.keys()) + list(ap.keys()))):
            bv = bp.get(pkg)
            av = ap.get(pkg)
            if bv and av and bv == av:
                unchanged.append((proj, tfm, pkg, av))
            elif bv and av and bv != av:
                changes.append((proj, tfm, pkg, bv, av, 'Aligned to highest version'))
            elif bv and not av:
                changes.append((proj, tfm, pkg, bv, '-', 'Removed'))
            elif not bv and av:
                changes.append((proj, tfm, pkg, '-', av, 'Added'))

print('CHANGES:')
if changes:
    for c in changes:
        print(f'  {c[0]} ({c[1]}) | {c[2]} | {c[3]} -> {c[4]} | {c[5]}')
else:
    print('  None')

print()
print('UNCHANGED:')
for u in unchanged:
    print(f'  {u[0]} ({u[1]}) | {u[2]} | {u[3]}')
"

